class UnifiedCorrelationTests(unittest.TestCase):
 @classmethod
 def setUpClass(cls):
  cls.engine=create_engine("sqlite://",connect_args={"check_same_thread":False},poolclass=StaticPool);cls.factory=sessionmaker(bind=cls.engine)
  def override():
   db=cls.factory()
   try:yield db
   finally:db.close()
  app.dependency_overrides[get_db]=override;cls.client=TestClient(app)
 @classmethod
 def tearDownClass(cls):cls.client.close();app.dependency_overrides.clear();cls.engine.dispose()
 def setUp(self):Base.metadata.drop_all(self.engine);Base.metadata.create_all(self.engine);authenticate_admin(self.client,self.factory)
 def seed(self):
  with self.factory() as db:
   db.add(models.Target(name="Safe Target",base_url="https://example.com",domain="example.com",environment="test",authorization_confirmed=True));a=models.ApiAssessment(name="Safe API",description="local",source_type="openapi",status="completed",base_url="https://example.com",endpoint_count=0);db.add(a);db.commit()
 def test_normalization(self):
  self.assertEqual(normalize("domain","Example.COM.")[0],"example.com");self.assertEqual(normalize("ip_address","2001:0db8::1")[0],"2001:db8::1");self.assertEqual(normalize("email_address","User@Example.COM")[1],"Us***@example.com");u=normalize("url","https://user:pass@example.com/a?token=FAKE");self.assertEqual(len(u[0]),64);self.assertNotIn("user:pass",u[1]);self.assertNotIn("FAKE",u[1]);self.assertEqual(normalize("api_endpoint","get /users/{id}?token=x")[0],"GET /users/{id}")
  with self.assertRaises(ValueError):normalize("ip_address","not-ip")
 def test_sync_correlation_case_report_and_preservation(self):
  self.seed();first=self.client.post("/api/correlation/entities/sync").json();self.assertGreater(first["observations_created"],0);second=self.client.post("/api/correlation/entities/sync").json();self.assertEqual(second["observations_created"],0);self.assertGreater(second["observations_reused"],0)
  entities=self.client.get("/api/correlation/entities").json();entity=next(x for x in entities["items"] if x["entity_type"]=="domain");self.assertEqual(entity["source_module_count"],2);run=self.client.post("/api/correlation/matches/run").json();self.assertGreater(run["matches_created"],0);rerun=self.client.post("/api/correlation/matches/run").json();self.assertEqual(rerun["matches_created"],0)
  match=self.client.get("/api/correlation/matches").json()[0];case=self.client.post(f"/api/correlation/matches/{match['id']}/create-case").json();same=self.client.post(f"/api/correlation/matches/{match['id']}/create-case").json();self.assertEqual(case["id"],same["id"]);cid=case["id"]
  note=self.client.post(f"/api/correlation/cases/{cid}/notes",json={"note_text":"token=FAKE_SECRET","author_label":"Analyst"}).json();self.assertNotIn("FAKE_SECRET",note["note_text"]);action=self.client.post(f"/api/correlation/cases/{cid}/actions",json={"title":"Review related records"});self.assertEqual(action.status_code,200)
  self.client.patch(f"/api/correlation/cases/{cid}",json={"priority":"P1","status":"investigating"});report=self.client.post(f"/api/correlation/cases/{cid}/reports").json();self.assertEqual(len(report["summary"]["sections"]),17);self.assertNotIn("<a ",report["html_content"]);self.assertIn("no indicators",report["html_content"])
  self.assertEqual(self.client.patch(f"/api/correlation/cases/{cid}",json={"status":"resolved"}).status_code,422);self.assertEqual(self.client.patch(f"/api/correlation/cases/{cid}",json={"status":"resolved","resolution_summary":"Validated local relationship"}).status_code,200);self.assertEqual(self.client.patch(f"/api/correlation/cases/{cid}",json={"status":"investigating"}).status_code,200);timeline=self.client.get(f"/api/correlation/cases/{cid}/timeline").json();self.assertGreaterEqual(len(timeline),7)
  before=self.client.get("/api/targets/").json();self.client.delete(f"/api/correlation/cases/{cid}");self.assertEqual(self.client.get("/api/targets/").json(),before);dash=self.client.get("/api/dashboard/summary").json();self.assertGreaterEqual(dash["multi_module_entities"],1);self.assertEqual(self.client.get("/api/search/",params={"q":"example"}).status_code,200)
