 def test_overdue_failure_creates_no_success_notification(self):
  case=self.client.post("/api/correlation/cases",json={"title":"Failure-safe overdue check","summary":"Local"}).json();past=(datetime.now(timezone.utc)-timedelta(days=1)).isoformat();self.client.post(f"/api/correlation/cases/{case['id']}/actions",json={"title":"Local action","due_at":past});before=len(self.client.get("/api/notifications/").json())
  with patch("app.modules.unified_correlation.service.notify",side_effect=RuntimeError("local notification failure")):
   result=self.client.post("/api/correlation/actions/check-overdue").json()
  self.assertEqual(result["notifications_created"],0);self.assertEqual(len(result["errors"]),1);self.assertEqual(len(self.client.get("/api/notifications/").json()),before)
