 def test_api_adapter_redacts_observations_without_mutating_sources(self):
  with self.factory() as db:
   assessment=models.ApiAssessment(name="Adapter source",source_type="manual",status="draft");db.add(assessment);db.flush();role=models.ApiRole(assessment_id=assessment.id,name="Operator token=FAKE_ADAPTER_SECRET",privilege_level="user");db.add(role);db.commit();role_id=role.id;snapshot=(role.name,role.privilege_level,role.assessment_id)
  result=self.client.post("/api/correlation/entities/sync",params={"source_module":"api_security"}).json();self.assertEqual(result["per_record_type_counts"].get("api_role"),1)
  with self.factory() as db:
   role=db.query(models.ApiRole).filter_by(id=role_id).one();self.assertEqual((role.name,role.privilege_level,role.assessment_id),snapshot);observations=db.query(models.EntityObservation).filter_by(source_record_type="api_role").all();self.assertEqual(len(observations),1);self.assertNotIn("FAKE_ADAPTER_SECRET",json.dumps([(x.title_snapshot,x.evidence_snapshot) for x in observations]))
